async (params, browser) => {
  // Open Jira issue
  await browser.open(`${params.jira_url}/browse/${params.issue_key}`)

  // Let page load
  await browser.wait(2000)

  // Assign issue via REST API
  const result = await browser.evaluate(`const baseUrl = params.jira_url.replace(/\/$/, ''); const query = params.assignee_query; let accountId = null; if (query) { const uResp = await fetch(baseUrl + '/rest/api/3/user/search?query=' + encodeURIComponent(query) + '&maxResults=1', { credentials: 'same-origin' }); if (!uResp.ok) throw new Error('User search failed: ' + uResp.status); const users = await uResp.json(); if (users.length === 0) return { success: false, message: 'No user found matching: ' + query }; accountId = users[0].accountId; } const resp = await fetch(baseUrl + '/rest/api/3/issue/' + params.issue_key + '/assignee', { method: 'PUT', headers: { 'Content-Type': 'application/json' }, credentials: 'same-origin', body: JSON.stringify({ accountId: accountId }) }); if (!resp.ok) { const err = await resp.text(); throw new Error('Assign failed: ' + resp.status + ' ' + err); } return { success: true, key: '' + params.issue_key + '', assignee: query || 'Unassigned' }`)

  return result
}
